// SPDX-License-Identifier: Apache-2.0
pragma solidity 0.8.20;

import "../interface/IConnector.sol";
import { NoyaGovernanceBase } from "../governance/NoyaGovernanceBase.sol";
import { PositionRegistry, PositionBP } from "../accountingManager/Registry.sol";
import "@openzeppelin/contracts-5.0/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts-5.0/token/ERC721/utils/ERC721Holder.sol";
import { SwapAndBridgeHandler, SwapRequest } from "../helpers/SwapHandler/GenericSwapAndBridgeHandler.sol";
import "../interface/valueOracle/INoyaValueOracle.sol";
import "../governance/Watchers.sol";
import "@openzeppelin/contracts-5.0/token/ERC721/IERC721Receiver.sol";
import "@openzeppelin/contracts-5.0/utils/ReentrancyGuard.sol";

struct BaseConnectorCP {
    PositionRegistry registry;
    uint256 vaultId;
    SwapAndBridgeHandler swapHandler;
    INoyaValueOracle valueOracle;
}

contract BaseConnector is NoyaGovernanceBase, IConnector, ReentrancyGuard {
    using SafeERC20 for IERC20;

    SwapAndBridgeHandler public swapHandler;
    INoyaValueOracle public valueOracle;

    uint256 public MINIMUM_HEALTH_FACTOR = 15e17;
    uint256 public minimumHealthFactor;

    uint256 public DUST_LEVEL = 1;

    constructor(BaseConnectorCP memory params) NoyaGovernanceBase(params.registry, params.vaultId) {
        swapHandler = params.swapHandler;
        valueOracle = params.valueOracle;
        minimumHealthFactor = MINIMUM_HEALTH_FACTOR;
    }

    /**
     * @notice Updates the minimum health factor required for operations
     * @dev Can only be called by the contract maintainer
     * @param _minimumHealthFactor The new minimum health factor
     * @dev for the connectors that borrowing is allowed, the health factor should be higher than this value (so we keep a safe margin)
     */
    function updateMinimumHealthFactor(uint256 _minimumHealthFactor) external onlyMaintainer {
        if (_minimumHealthFactor < MINIMUM_HEALTH_FACTOR) {
            revert IConnector_LowHealthFactor(_minimumHealthFactor);
        }
        minimumHealthFactor = _minimumHealthFactor;
        emit MinimumHealthFactorUpdated(_minimumHealthFactor);
    }

    /**
     * @notice Updates the SwapAndBridgeHandler contract address
     * @param _swapHandler The new SwapAndBridgeHandler contract address
     * @dev swap handler is used to execute swaps and bridges
     */
    function updateSwapHandler(address payable _swapHandler) external onlyMaintainer {
        swapHandler = SwapAndBridgeHandler(_swapHandler);
        emit SwapHandlerUpdated(_swapHandler);
    }
    /**
     * @notice Updates the ValueOracle contract address
     * @param _valueOracle The new ValueOracle contract address
     */

    function updateValueOracle(address _valueOracle) external onlyMaintainer {
        valueOracle = INoyaValueOracle(_valueOracle);
        emit ValueOracleUpdated(_valueOracle);
    }
    /**
     * @notice Sends tokens to a trusted address
     * @param token The token address
     * @param amount The amount of tokens to send
     * @param caller The caller address (used to verify the caller is this contract in the swapHandler)
     * @param data Additional data used in the transfer
     * @return The actual amount of tokens sent
     * @dev This function is used to send tokens to trusted addresses (vault, accounting manager, swap handler)
     * @dev in case the caller is the accounting manager, the function will check with the watcher contract the number of tokens to withdraw
     * @dev in case the caller is a connector, the function will check if the caller is an active connector
     * @dev in case the caller is the swap handler, the function will check if the caller is a valid route
     */

    function sendTokensToTrustedAddress(address token, uint256 amount, address caller, bytes memory data)
        external
        returns (uint256)
    {
        emit TransferTokensToTrustedAddress(token, amount, caller, data);
        (address accountingManager,) = registry.getVaultAddresses(vaultId);
        if (msg.sender == accountingManager) {
            (,,,, address watcherContract,) = registry.getGovernanceAddresses(vaultId);

            (uint256 newAmount, bytes memory newData) = abi.decode(data, (uint256, bytes));
            Watchers(watcherContract).verifyRemoveLiquidity(amount, newAmount, newData);

            IERC20(token).safeTransfer(address(accountingManager), newAmount);
            amount = newAmount;
        } else if (registry.isAnActiveConnector(vaultId, msg.sender) || msg.sender == registry.flashLoan()) {
            IERC20(token).safeTransfer(address(msg.sender), amount);
        } else {
            uint256 routeId = abi.decode(data, (uint256));
            swapHandler.verifyRoute(routeId, msg.sender);
            if (caller != address(this)) revert IConnector_InvalidAddress(caller);
            IERC20(token).safeTransfer(msg.sender, amount);
        }
        _updateTokenInRegistry(token);
        return amount;
    }
    /**
     * @notice Transfers position to another connector
     * @param tokens The addresses of tokens involved
     * @param amounts The amounts for each token
     * @param data Additional data for liquidity adding
     * @param connector The target connector address
     * @dev the flow is :
     * @dev 1. check if the connector is active
     * @dev 2. call the addLiquidity function in the target connector
     * @dev 3. destination connector will call the sendTokensToTrustedAddress function to transfer the tokens
     * @dev 4. update the position in the registry for both connectors
     */

    function transferPositionToAnotherConnector(
        address[] memory tokens,
        uint256[] memory amounts,
        bytes memory data,
        address connector
    ) external onlyManager nonReentrant {
        emit TransferPositionToConnector(tokens, amounts, connector, data);
        if (registry.isAnActiveConnector(vaultId, connector)) {
            IConnector(connector).addLiquidity(tokens, amounts, data);
        }
    }

    // @dev the following functions are used to manage holding tokens in the registry
    function _updateTokenInRegistry(address token, bool remove) internal {
        (address accountingManager,) = registry.getVaultAddresses(vaultId);
        // the value function is inside the accounting manager contract (so we can use the accounting manager address as the calculator connector)
        bytes32 positionId = registry.calculatePositionId(accountingManager, 0, abi.encode(token));
        // if the token is not in the registry, we add it or remove it if the remove flag is true
        uint256 positionIndex =
            registry.getHoldingPositionIndex(vaultId, positionId, address(this), abi.encode(address(this)));
        if ((positionIndex == 0 && !remove) || (positionIndex > 0 && remove)) {
            emit UpdateTokenInRegistry(token, remove);
            registry.updateHoldingPosition(vaultId, positionId, abi.encode(address(this)), "", remove);
        }
    }
    /**
     * @notice Updates the token registry to reflect the current balance of a specified token. It can add a new token to the registry or remove a token with zero balance.
     * @dev This function is called to ensure the registry is accurate after liquidity is added, removed, or swaps are performed. It should reflect the current state of tokens held by this connector.
     * @param token The address of the token to update in the registry.
     */

    function updateTokenInRegistry(address token) public onlyManager {
        _updateTokenInRegistry(token);
    }
    /// @notice adds or removes the token position to the registry based on the balance of the token

    function _updateTokenInRegistry(address token) internal {
        _updateTokenInRegistry(token, IERC20(token).balanceOf(address(this)) == 0);
    }
    /**
     * @notice Adds liquidity to this connector
     * @param tokens The addresses of tokens to add as liquidity
     * @param amounts The amounts of each token to add
     * @param data Additional data needed for adding liquidity
     * @dev This function is called to add liquidity to this connector. It should be implemented in the connector contract to handle the specific liquidity adding process for the connector by overriding the _addLiquidity function (optional).
     */

    function addLiquidity(address[] memory tokens, uint256[] memory amounts, bytes memory data)
        external
        override
        nonReentrant
    {
        if (!registry.isAddressTrusted(vaultId, msg.sender)) {
            revert IConnector_InvalidAddress(msg.sender);
        }

        for (uint256 i = 0; i < tokens.length; i++) {
            // gather all of the tokens
            uint256 _balance = IERC20(tokens[i]).balanceOf(address(this));
            ITokenTransferCallBack(msg.sender).sendTokensToTrustedAddress(tokens[i], amounts[i], msg.sender, "");
            uint256 _balanceAfter = IERC20(tokens[i]).balanceOf(address(this));
            if (_balanceAfter < amounts[i] + _balance) {
                revert IConnector_InsufficientDepositAmount(_balanceAfter - _balance, amounts[i]);
            }
        }
        _addLiquidity(tokens, amounts, data); // call the specific implementation if the connector needs to do something after the liquidity is added

        for (uint256 i = 0; i < tokens.length; i++) {
            _updateTokenInRegistry(tokens[i]); // update the token in the registry
        }
        emit AddLiquidity(tokens, amounts, data);
    }

    /**
     * @notice Executes swaps for holdings from one set of tokens to another
     * @param tokensIn The addresses of input tokens for the swaps
     * @param tokensOut The addresses of output tokens for the swaps
     * @param amountsIn The input amounts for each swap
     * @param swapData The data required for executing each swap
     * @param routeIds The route IDs for each swap (used to verify the route in the swapHandler)
     * @dev the check slippage is set to true, so the swapHandler will revert if the slippage is higher than the allowed
     */
    function swapHoldings(
        address[] memory tokensIn,
        address[] memory tokensOut,
        uint256[] memory amountsIn,
        bytes[] memory swapData,
        uint256[] memory routeIds
    ) external onlyManager nonReentrant {
        for (uint256 i = 0; i < tokensIn.length; i++) {
            _executeSwap(
                SwapRequest(address(this), routeIds[i], amountsIn[i], tokensIn[i], tokensOut[i], swapData[i], true, 0)
            );
            _updateTokenInRegistry(tokensIn[i]);
            _updateTokenInRegistry(tokensOut[i]);
            emit SwapHoldings(tokensIn[i], tokensOut[i], amountsIn[i], swapData[i]);
        }
    }

    function _executeSwap(SwapRequest memory swapRequest) internal returns (uint256 amountOut) {
        amountOut = swapHandler.executeSwap(swapRequest);
    }
    /**
     * @notice Retrieves the underlying tokens associated with a position type and data
     * @param positionTypeId The type ID of the position
     * @param data Additional data relevant to the position
     * @return An array of addresses of the underlying tokens
     * @dev each connector should implement this function to return the underlying tokens for the position type and data
     */

    function getUnderlyingTokens(uint256 positionTypeId, bytes memory data) public view returns (address[] memory) {
        if (positionTypeId == 0) {
            address[] memory tokens = new address[](1);
            tokens[0] = abi.decode(data, (address));
            return tokens;
        }
        return _getUnderlyingTokens(positionTypeId, data);
    }
    /**
     * @notice the TVLHelper library uses this function to calculate the TVL of a position
     * @param p The holding position information
     * @param baseToken The base currency for the TVL calculation
     * @return The TVL of the position in the base currency units
     * @dev each connector should implement this function to calculate the TVL of the position
     * @dev the holding position is the data that was sent to the connector to create the position
     */

    function getPositionTVL(HoldingPI memory p, address baseToken) public view returns (uint256) {
        return _getPositionTVL(p, baseToken);
    }

    function _getValue(address token, address baseToken, uint256 amount) internal view returns (uint256) {
        if (token == baseToken) {
            return amount;
        }
        if (amount == 0) {
            return 0;
        }
        return valueOracle.getValue(token, baseToken, amount);
    }

    function _getUnderlyingTokens(uint256, bytes memory) public view virtual returns (address[] memory) {
        return new address[](0);
    }

    function _addLiquidity(address[] memory, uint256[] memory, bytes memory) internal virtual returns (bool) {
        return true;
    }

    function _getPositionTVL(HoldingPI memory, address) public view virtual returns (uint256 tvl) {
        return 0;
    }
    /// @notice is used to approve the _spender to spend the _amount of the _token
    /// @dev It uses the forceApprove function so it's safe to use it with tokens with special approval logic (USDT)

    function _approveOperations(address _token, address _spender, uint256 _amount) internal virtual {
        uint256 currentAllowance = IERC20(_token).allowance(address(this), _spender);
        if (currentAllowance >= _amount) {
            return;
        }
        IERC20(_token).forceApprove(_spender, _amount);
    }

    function _revokeApproval(address _token, address _spender) internal virtual {
        IERC20(_token).forceApprove(_spender, 0);
    }
}

// SPDX-License-Identifier: MIT
pragma solidity 0.8.23;

import {Receiver} from "solady/accounts/Receiver.sol";
import {UUPSUpgradeable} from "solady/utils/UUPSUpgradeable.sol";
import {SignatureCheckerLib} from "solady/utils/SignatureCheckerLib.sol";
import {UserOperation, UserOperationLib} from "account-abstraction/interfaces/UserOperation.sol";
import {WebAuthn} from "../WebAuthnSol/WebAuthn.sol";

import {ERC1271} from "./ERC1271.sol";
import {MultiOwnable} from "./MultiOwnable.sol";

/// @title Coinbase Smart Wallet
///
/// @notice ERC4337-compatible smart contract wallet, based on Solady ERC4337 account implementation
///         with inspiration from Alchemy's LightAccount and Daimo's DaimoAccount.
///
/// @author Coinbase (https://github.com/coinbase/smart-wallet)
/// @author Solady (https://github.com/vectorized/solady/blob/main/src/accounts/ERC4337.sol)
contract CoinbaseSmartWallet is MultiOwnable, UUPSUpgradeable, Receiver, ERC1271 {
    /// @notice Wrapper struct, used during signature validation, tie a signature with its signer.
    struct SignatureWrapper {
        /// @dev The index indentifying owner (see MultiOwnable) who signed.
        uint256 ownerIndex;
        /// @dev An ABI encoded ECDSA signature (r, s, v) or WebAuthnAuth struct.
        bytes signatureData;
    }

    /// @notice Wrapper struct, used in `executeBatch`, describing a raw call to execute.
    struct Call {
        /// @dev The target address to call.
        address target;
        /// @dev The value to associate with the call.
        uint256 value;
        /// @dev The raw call data.
        bytes data;
    }

    /// @notice Reserved nonce key (upper 192 bits of `UserOperation.nonce`) for cross-chain replayable
    ///         transactions.
    ///
    /// @dev Helps enforce sequential sequencing of replayable transactions.
    uint256 public constant REPLAYABLE_NONCE_KEY = 8453;

    /// @notice Thrown when trying to re-initialize an account.
    error Initialized();

    /// @notice Thrown when executing a `UserOperation` that requires the chain ID to be validated
    ///         but this validation has been omitted.
    ///
    /// @dev Whitelisting of `UserOperation`s that are allowed to skip the chain ID validation is
    ///      based on their call selectors (see `canSkipChainIdValidation()`).
    ///
    /// @param selector The user operation call selector that raised the error.
    error SelectorNotAllowed(bytes4 selector);

    /// @notice Thrown during a `UserOperation` validation when its key is invalid.
    ///
    /// @dev The `UserOperation` key validation is based on the `UserOperation` call selector.
    ///
    /// @param key The invalid `UserOperation` key.
    error InvalidNonceKey(uint256 key);

    /// @notice Reverts if the caller is not the EntryPoint.
    modifier onlyEntryPoint() virtual {
        if (msg.sender != entryPoint()) {
            revert Unauthorized();
        }

        _;
    }

    /// @notice Reverts if the caller is neither the EntryPoint, the owner, nor the account itself.
    modifier onlyEntryPointOrOwner() virtual {
        if (msg.sender != entryPoint()) {
            _checkOwner();
        }

        _;
    }

    /// @notice Sends to the EntryPoint (i.e. `msg.sender`) the missing funds for this transaction.
    ///
    /// @dev Subclass MAY override this modifier for better funds management (e.g. send to the
    ///      EntryPoint more than the minimum required, so that in future transactions it will not
    ///      be required to send again).
    ///
    /// @param missingAccountFunds The minimum value this modifier should send the EntryPoint which
    ///                            MAY be zero, in case there is enough deposit, or the userOp has a
    ///                            paymaster.
    modifier payPrefund(uint256 missingAccountFunds) virtual {
        _;

        assembly ("memory-safe") {
            if missingAccountFunds {
                // Ignore failure (it's EntryPoint's job to verify, not the account's).
                pop(call(gas(), caller(), missingAccountFunds, codesize(), 0x00, codesize(), 0x00))
            }
        }
    }

    constructor() {
        // Implementation should not be initializable (does not affect proxies which use their own storage).
        bytes[] memory owners = new bytes[](1);
        owners[0] = abi.encode(address(0));
        _initializeOwners(owners);
    }

    /// @notice Initializes the account with the the given owners.
    ///
    /// @dev Reverts if the account has already been initialized.
    ///
    /// @param owners The initial array of owners to initialize this account with.
    function initialize(bytes[] calldata owners) public payable virtual {
        if (nextOwnerIndex() != 0) {
            revert Initialized();
        }

        _initializeOwners(owners);
    }

    /// @notice Custom implemenentation of the ERC-4337 `validateUserOp` method. The EntryPoint will
    ///         make the call to the recipient only if this validation call returns successfully.
    ///         See `IAccount.validateUserOp()`.
    ///
    /// @dev Signature failure should be reported by returning 1 (see: `_validateSignature()`). This
    ///      allows making a "simulation call" without a valid signature. Other failures (e.g. nonce
    ///      mismatch, or invalid signature format) should still revert to signal failure.
    /// @dev Reverts if the `UserOperation` key is invalid.
    /// @dev Reverts if the signature verification fails (except for the case mentionned earlier).
    ///
    /// @param userOp              The `UserOperation` to validate.
    /// @param userOpHash          The `UserOperation` hash (including the chain ID).
    /// @param missingAccountFunds The missing account funds that must be deposited on the Entrypoint.
    ///
    /// @return validationData The encoded `ValidationData` structure.
    function validateUserOp(UserOperation calldata userOp, bytes32 userOpHash, uint256 missingAccountFunds)
        public
        payable
        virtual
        onlyEntryPoint
        payPrefund(missingAccountFunds)
        returns (uint256 validationData)
    {
        uint256 key = userOp.nonce >> 64;

        // 0xbf6ba1fc = bytes4(keccak256("executeWithoutChainIdValidation(bytes)"))
        if (userOp.callData.length >= 4 && bytes4(userOp.callData[0:4]) == 0xbf6ba1fc) {
            userOpHash = getUserOpHashWithoutChainId(userOp);
            if (key != REPLAYABLE_NONCE_KEY) {
                revert InvalidNonceKey(key);
            }
        } else {
            if (key == REPLAYABLE_NONCE_KEY) {
                revert InvalidNonceKey(key);
            }
        }

        // Return 0 if the recovered address matches the owner.
        if (_validateSignature(userOpHash, userOp.signature)) {
            return 0;
        }

        // Else return 1, which is equivalent to:
        // `(uint256(validAfter) << (160 + 48)) | (uint256(validUntil) << 160) | (success ? 0 : 1)`
        // where `validUntil` is 0 (indefinite) and `validAfter` is 0.
        return 1;
    }

    /// @notice Execute the given call from this account to this account (i.e., self call).
    ///
    /// @dev Can only be called by the Entrypoint.
    /// @dev Reverts if the given call is not authorized to skip the chain ID validtion.
    /// @dev `validateUserOp()` will recompute the `userOpHash` without the chain ID befor validatin
    ///      it if the `UserOperation` aims at executing this function. This allows certain operations
    ///      to be replayed for all accounts sharing the same address across chains. E.g. This may be
    ///      useful for syncing owner changes.
    ///
    /// @param data The `UserOperation` raw call data of the  execute.
    function executeWithoutChainIdValidation(bytes calldata data) public payable virtual onlyEntryPoint {
        bytes4 selector = bytes4(data[0:4]);
        if (!canSkipChainIdValidation(selector)) {
            revert SelectorNotAllowed(selector);
        }

        _call(address(this), 0, data);
    }

    /// @notice Execute the given call from this account.
    ///
    /// @dev Can only be called by the Entrypoint or an owner of this account (including itself).
    ///
    /// @param target The target call address.
    /// @param value  The call value to user.
    /// @param data   The raw call data.
    function execute(address target, uint256 value, bytes calldata data) public payable virtual onlyEntryPointOrOwner {
        _call(target, value, data);
    }

    /// @notice Execute the given list of calls from this account.
    ///
    /// @dev Can only be called by the Entrypoint or an owner of this account (including itself).
    ///
    /// @param calls The list of `Call`s to execute.
    function executeBatch(Call[] calldata calls) public payable virtual onlyEntryPointOrOwner {
        for (uint256 i; i < calls.length;) {
            _call(calls[i].target, calls[i].value, calls[i].data);
            unchecked {
                ++i;
            }
        }
    }

    /// @notice Returns the address of the EntryPoint v0.6.
    ///
    /// @return The address of the EntryPoint v0.6
    function entryPoint() public view virtual returns (address) {
        return 0x5FF137D4b0FDCD49DcA30c7CF57E578a026d2789;
    }

    /// @notice Computes the hash of the `UserOperation` in the same way as EntryPoint v0.6, but
    ///         leaves out the chain ID.
    ///
    /// @dev This allows accounts to sign a hash that can be used on many chains.
    ///
    /// @param userOp The `UserOperation` to compute the hash for.
    ///
    /// @return userOpHash The `UserOperation` hash, not including the chain ID.
    function getUserOpHashWithoutChainId(UserOperation calldata userOp)
        public
        view
        virtual
        returns (bytes32 userOpHash)
    {
        return keccak256(abi.encode(UserOperationLib.hash(userOp), entryPoint()));
    }

    /// @notice Returns the implementation of the ERC1967 proxy.
    ///
    /// @return $ The address of implementation contract.
    function implementation() public view returns (address $) {
        assembly {
            $ := sload(_ERC1967_IMPLEMENTATION_SLOT)
        }
    }

    /// @notice Check if the given function selector is whitelisted to skip the chain ID validation.
    ///
    /// @param functionSelector The function selector to check.
    ////
    /// @return `true` is the function selector is whitelisted to skip the chain ID validation, else `false`.
    function canSkipChainIdValidation(bytes4 functionSelector) public pure returns (bool) {
        if (
            functionSelector == MultiOwnable.addOwnerPublicKey.selector
                || functionSelector == MultiOwnable.addOwnerAddress.selector
                || functionSelector == MultiOwnable.removeOwnerAtIndex.selector
                || functionSelector == UUPSUpgradeable.upgradeToAndCall.selector
        ) {
            return true;
        }
        return false;
    }

    /// @notice Execute the given call from this account.
    ///
    /// @dev Reverts if the call reverted.
    /// @dev Impl taken from https://github.com/alchemyplatform/light-account/blob/main/src/LightAccount.sol#L347
    ///
    /// @param target The target call address.
    /// @param value  The call value to user.
    /// @param data   The raw call data.
    function _call(address target, uint256 value, bytes memory data) internal {
        (bool success, bytes memory result) = target.call{value: value}(data);
        if (!success) {
            assembly ("memory-safe") {
                revert(add(result, 32), mload(result))
            }
        }
    }

    /// @inheritdoc ERC1271
    ///
    /// @dev Used both for classic ERC-1271 signature AND `UserOperation` validations.
    /// @dev Reverts if the signer (based on the `ownerIndex`) is not compatible with the signature.
    /// @dev Reverts if the signature does not correspond to an ERC-1271 signature or to the abi
    ///      encoded version of a `WebAuthnAuth` struct.
    /// @dev Does NOT revert if the signature verification fails to allow making a "simulation call"
    ///      without a valid signature.
    ///
    /// @param signature The abi encoded `SignatureWrapper` struct.
    function _validateSignature(bytes32 message, bytes calldata signature)
        internal
        view
        virtual
        override
        returns (bool)
    {
        SignatureWrapper memory sigWrapper = abi.decode(signature, (SignatureWrapper));
        bytes memory ownerBytes = ownerAtIndex(sigWrapper.ownerIndex);

        if (ownerBytes.length == 32) {
            if (uint256(bytes32(ownerBytes)) > type(uint160).max) {
                // technically should be impossible given owners can only be added with
                // addOwnerAddress and addOwnerPublicKey, but we leave incase of future changes.
                revert InvalidEthereumAddressOwner(ownerBytes);
            }

            address owner;
            assembly ("memory-safe") {
                owner := mload(add(ownerBytes, 32))
            }

            return SignatureCheckerLib.isValidSignatureNow(owner, message, sigWrapper.signatureData);
        }

        if (ownerBytes.length == 64) {
            (uint256 x, uint256 y) = abi.decode(ownerBytes, (uint256, uint256));

            WebAuthn.WebAuthnAuth memory auth = abi.decode(sigWrapper.signatureData, (WebAuthn.WebAuthnAuth));

            return WebAuthn.verify({challenge: abi.encode(message), requireUV: false, webAuthnAuth: auth, x: x, y: y});
        }

        revert InvalidOwnerBytesLength(ownerBytes);
    }

    /// @inheritdoc UUPSUpgradeable
    ///
    /// @dev Authorization logic is only based on the sender being an owner of this account.
    function _authorizeUpgrade(address) internal view virtual override(UUPSUpgradeable) onlyOwner {}

    /// @inheritdoc ERC1271
    function _domainNameAndVersion() internal pure override(ERC1271) returns (string memory, string memory) {
        return ("Coinbase Smart Wallet", "1");
    }
}

// SPDX-License-Identifier: GPL-2.0-or-later

pragma solidity ^0.7.6;

import "@openzeppelin/contracts/math/SafeMath.sol";

import "./GraphTokenUpgradeable.sol";
import "../../arbitrum/IArbToken.sol";

/**
 * @title L2 Graph Token Contract
 * @dev Provides the L2 version of the GRT token, meant to be minted/burned
 * through the L2GraphTokenGateway.
 */
contract L2GraphToken is GraphTokenUpgradeable, IArbToken {
    using SafeMath for uint256;

    // Address of the gateway (on L2) that is allowed to mint tokens
    address public gateway;
    // Address of the corresponding Graph Token contract on L1
    address public override l1Address;

    // Emitted when the bridge / gateway has minted new tokens, i.e. tokens were transferred to L2
    event BridgeMinted(address indexed account, uint256 amount);
    // Emitted when the bridge / gateway has burned tokens, i.e. tokens were transferred back to L1
    event BridgeBurned(address indexed account, uint256 amount);
    // Emitted when the address of the gateway has been updated
    event GatewaySet(address gateway);
    // Emitted when the address of the Graph Token contract on L1 has been updated
    event L1AddressSet(address l1Address);

    /**
     * @dev Checks that the sender is the L2 gateway from the L1/L2 token bridge
     */
    modifier onlyGateway() {
        require(msg.sender == gateway, "NOT_GATEWAY");
        _;
    }

    /**
     * @dev L2 Graph Token Contract initializer.
     * Note some parameters have to be set separately as they are generally
     * not expected to be available at initialization time:
     * - gateway using setGateway
     * - l1Address using setL1Address
     * @param _owner Governance address that owns this contract
     */
    function initialize(address _owner) external onlyImpl {
        require(_owner != address(0), "Owner must be set");
        // Initial supply hard coded to 0 as tokens are only supposed
        // to be minted through the bridge.
        GraphTokenUpgradeable._initialize(_owner, 0);
    }

    /**
     * @dev Sets the address of the L2 gateway allowed to mint tokens
     * @param _gw Address for the L2GraphTokenGateway that will be allowed to mint tokens
     */
    function setGateway(address _gw) external onlyGovernor {
        require(_gw != address(0), "INVALID_GATEWAY");
        gateway = _gw;
        emit GatewaySet(gateway);
    }

    /**
     * @dev Sets the address of the counterpart token on L1
     * @param _addr Address for the GraphToken contract on L1
     */
    function setL1Address(address _addr) external onlyGovernor {
        require(_addr != address(0), "INVALID_L1_ADDRESS");
        l1Address = _addr;
        emit L1AddressSet(_addr);
    }

    /**
     * @dev Increases token supply, only callable by the L1/L2 bridge (when tokens are transferred to L2)
     * @param _account Address to credit with the new tokens
     * @param _amount Number of tokens to mint
     */
    function bridgeMint(address _account, uint256 _amount) external override onlyGateway {
        _mint(_account, _amount);
        emit BridgeMinted(_account, _amount);
    }

    /**
     * @dev Decreases token supply, only callable by the L1/L2 bridge (when tokens are transferred to L1).
     * @param _account Address from which to extract the tokens
     * @param _amount Number of tokens to burn
     */
    function bridgeBurn(address _account, uint256 _amount) external override onlyGateway {
        burnFrom(_account, _amount);
        emit BridgeBurned(_account, _amount);
    }
}

